   SET 

       ORG_ID = #{orgId}


     , CODE_CTGR_NM = #{codeCtgrNm}


     , CODE_CTGR_DESC = #{codeCtgrDesc}


     , CODE_CTGR_ODR = #{codeCtgrOdr}


     , USEYN = #{useYn}

     , MDFR_ID = #{mdfrId}
     , MOD_DTTM = FN_DTTM()
 WHERE ORG_ID = #{orgId}
   AND CTGRCD = #{codeCtgrCd}

